### 2) `get_rune` resolves call/member expressions and ignores shadowed rune names

`packages/svelte/src/compiler/phases/scope.js`
```js
721:  * Returns the name of the rune if the given expression is a `CallExpression` using a rune.
722:  * @param {Node | null | undefined} node
723:  * @param {Scope} scope
724:  */
725: export function get_rune(node, scope) {
726: 	if (!node) return null;
727: 	if (node.type !== 'CallExpression') return null;
728: 
729: 	let n = node.callee;
730: 
731: 	let joined = '';
732: 
733: 	while (n.type === 'MemberExpression') {
734: 		if (n.computed) return null;
735: 		if (n.property.type !== 'Identifier') return null;
736: 		joined = '.' + n.property.name + joined;
737: 		n = n.object;
738: 	}
739: 
740: 	if (n.type === 'CallExpression' && n.callee.type === 'Identifier') {
741: 		joined = '()' + joined;
742: 		n = n.callee;
743: 	}
744: 
745: 	if (n.type !== 'Identifier') return null;
746: 
747: 	joined = n.name + joined;
748: 
749: 	if (!is_rune(joined)) return null;
750: 
751: 	const binding = scope.get(n.name);
752: 	if (binding !== null) return null; // rune name, but references a variable or store
753: 
754: 	return joined;
755: }
```

